// §W1  EQUIP WEAPON QUALITY SYSTEM — 装备武器品质系统
// ═══════════════════════════════════════════════════════

// 4种品质，白→蓝→紫→金，同武器同品质×2可融合升一级，金色无法继续融合
const EQUIP_QUALITY = {
  order: ['white', 'blue', 'purple', 'gold'],
  defs: {
    white:  { name:'白', label:'普通', color:'#dddddd', textColor:'#cccccc', canFuse:true  },
    blue:   { name:'蓝', label:'精良', color:'#5599ff', textColor:'#5599ff', canFuse:true  },
    purple: { name:'紫', label:'史诗', color:'#aa55ff', textColor:'#aa55ff', canFuse:true  },
    gold:   { name:'金', label:'传说', color:'#ffdd44', textColor:'#ffcc00', canFuse:false },
  },
  fuseCount: 2,         // 同武器同品质需要2件才能融合
  // 取得下一品质，金色返回 null
  nextQuality(q) {
    const idx = this.order.indexOf(q);
    return (idx >= 0 && idx < this.order.length - 1) ? this.order[idx + 1] : null;
  },
  // 是否可以融合
  canFuse(q) {
    return this.defs[q]?.canFuse ?? false;
  },
};

// ── 装备武器格子规则 ──────────────────────────────────
// - 格子满时自动检测可融合对（同武器同品质≥2）并融合
// - 全金色时商店无法再购买该武器
// - 融合逻辑由 game.js / ui.js 实现，此处仅定义规则常量
const EQUIP_SLOT_RULES = {
  autoFuseOnFull: true,   // 格子满时自动融合
  blockBuyIfAllGold: true,// 全格金色时禁止购买
};

// ── 武器刷新品质概率表（受幸运值影响） ─────────────────
// 权重顺序对应 EQUIP_QUALITY.order: [white, blue, purple, gold]
// 中间值线性插值；超出范围取边界值
const EQUIP_REFRESH_WEIGHTS = {
  table: [
    { luck:0,   w:[95, 5,  0,  0] },
    { luck:10,  w:[85, 12, 3,  0] },
    { luck:50,  w:[70, 20, 9,  1] },
    { luck:100, w:[50, 30, 15, 5] },
  ],
  // 返回对应幸运值的 [white, blue, purple, gold] 权重数组（浮点，使用前取整再归一化）
  getWeights(luck) {
    const t = this.table;
    const lv = Math.max(0, luck);
    if (lv <= t[0].luck) return [...t[0].w];
    if (lv >= t[t.length - 1].luck) return [...t[t.length - 1].w];
    for (let i = 0; i < t.length - 1; i++) {
      if (lv >= t[i].luck && lv <= t[i + 1].luck) {
        const frac = (lv - t[i].luck) / (t[i + 1].luck - t[i].luck);
        return t[i].w.map((a, j) => a + (t[i + 1].w[j] - a) * frac);
      }
    }
    return [...t[t.length - 1].w];
  },
  // 根据权重随机抽取一个品质 key
  rollQuality(luck) {
    const weights = this.getWeights(luck);
    const total = weights.reduce((s, v) => s + v, 0);
    let r = Math.random() * total;
    const keys = EQUIP_QUALITY.order;
    for (let i = 0; i < weights.length; i++) {
      r -= weights[i];
      if (r <= 0) return keys[i];
    }
    return keys[keys.length - 1];
  },
};

